function g(t){return t.toFixed(2).replace(".",",")+" h"}function a(t){if(!t)return "\u2013";let r=new Date(t),n=r.getHours().toString().padStart(2,"0"),o=r.getMinutes().toString().padStart(2,"0");return `${n}:${o}`}function u(t){if(!t)return "\u2013";let r=new Date(t),n=r.getDate().toString().padStart(2,"0"),o=(r.getMonth()+1).toString().padStart(2,"0");return `${n}.${o}.${r.getFullYear()}`}function c(t){return t?`${u(t)} ${a(t)}`:"\u2013"}function i(t){let r=Math.max(0,Math.floor(t/1e3)),n=Math.floor(r/3600).toString().padStart(2,"0"),o=Math.floor(r%3600/60).toString().padStart(2,"0"),e=(r%60).toString().padStart(2,"0");return `${n}:${o}:${e}`}function f(t){return t==null?"\u2014":t.toLocaleString("de-DE")+" km"}function s(t){return (t<0?"-":"")+i(Math.abs(t))}function m(t){let r=Math.round(t*60),n=Math.floor(r/60),o=(r%60).toString().padStart(2,"0");return `${n}:${o}`}export{a,c,f,g,m,s,u};